object Solution { def rate_limited(events: Seq[Seq[Any]], limit: Int, window: Int): Seq[Boolean] = { val accepted = scala.collection.mutable.Map[String, scala.collection.mutable.Queue[Int]](); events.map { event => val timestamp = asInt(event(0)); val userId = event(1).toString; val queue = accepted.getOrElseUpdate(userId, scala.collection.mutable.Queue[Int]()); while (queue.nonEmpty && queue.front <= timestamp - window) queue.dequeue(); if (queue.size < limit) { queue.enqueue(timestamp); true } else false } }; private def asInt(value: Any): Int = value match { case n: Int => n; case n: Long => n.toInt; case n: Double => n.toInt; case _ => 0 } }
